import java.util.*;

class SORTracker {
    private static class Location {
        String name;
        int score;
        Location(String name, int score) {
            this.name = name;
            this.score = score;
        }
    }

    private final PriorityQueue<Location> minHeap;
    private final PriorityQueue<Location> maxHeap;
    private int queryCount;

    public SORTracker() {
        minHeap = new PriorityQueue<>((a, b) -> {
            if (a.score != b.score) return Integer.compare(a.score, b.score);
            return b.name.compareTo(a.name);
        });
        maxHeap = new PriorityQueue<>((a, b) -> {
            if (a.score != b.score) return Integer.compare(b.score, a.score);
            return a.name.compareTo(b.name);
        });
        queryCount = 0;
    }

    public void add(String name, int score) {
        Location loc = new Location(name, score);
        minHeap.offer(loc);
        maxHeap.offer(minHeap.poll());
    }

    public String get() {
        queryCount++;
        while (maxHeap.size() > queryCount) {
            minHeap.offer(maxHeap.poll());
        }
        while (maxHeap.size() < queryCount) {
            maxHeap.offer(minHeap.poll());
        }
        return maxHeap.peek().name;
    }
}
```
efficiency: HIGH
time complexity: O(log N) per add and get
space complexity: O(N)
energy implications: LOW
explanation: Uses two heaps (min-heap and max-heap) to maintain the top-k locations in sorted order. Each add inserts into the min-heap and rebalances, while each get adjusts the heaps so the k-th best is always at the max-heap root. This yields logarithmic time per operation and minimal energy usage.

